function statusCard(){const t=S.stocks.filter(t=>null!=t.rev).length,s=S.stocks.filter(t=>null!=t.roe||null!=t.eps).length,a=S.stocks.filter(t=>null!=t.foreign||null!=t.inst).length,e="ready"===S.fundStatus?"ok":"error"===S.fundStatus?"bad":"",l="ready"===S.fundStatus?"基本面已更新":"partial"===S.fundStatus?"部分基本面資料":"error"===S.fundStatus?"基本面暫缺":"基本面載入中";return`<div class="card data-health"><div><b>資料完整度</b><div class="muted">月營收 ${t} 檔 · 財報 ${s} 檔 · 法人 ${a} 檔${S.fundPeriod?` · ${S.fundPeriod}`:""}</div></div><span class="status-pill ${e}">${l}</span></div>`}function disclaimer(){return`<div class="disclaimer">${DISCLAIMER}</div>`}function metric(t,s,a=""){return`<div class="metric"><small>${t}</small><b>${s}</b>${a?`<em>${a}</em>`:""}</div>`}function valueOrReason(t,s="",a="API 未回傳"){return null==t?reasonDash(a):`${fmt(t)}${s}`}function homePage(){const t=marketEnvironment(),s=(t,s,a)=>`<div class="card"><h3>${t}</h3><div class="rank-list">${s.slice(0,5).map((t,s)=>`<div class="rank clickable" data-detail="${t.symbol}"><b>${s+1}</b><span><b>${t.name}</b><small class="muted"> ${t.symbol}</small></span><b class="${cls(t.change)}">${a(t)}</b></div>`).join("")}</div></div>`,a=[...S.stocks].filter(t=>null!=t.rev).sort((t,s)=>s.rev-t.rev),e=[...S.stocks].filter(t=>null!=t.inst).sort((t,s)=>s.inst-t.inst),l=[...S.stocks].filter(opportunityEligible).sort((t,s)=>opportunityScore(s)-opportunityScore(t));return`<h2>盤後市場儀表板</h2><div class="muted">官方盤後資料整理，不是即時報價。</div>\n  <div class="grid">${metric("最新日期",S.date||"—")}${metric("上市股票",fmt(S.stocks.length,0))}</div>\n  <div class="card accent"><div class="head"><div><small class="muted">大盤環境</small><div class="price">${t.label}</div><div class="muted">上漲 ${t.up} · 下跌 ${t.down} · 平盤 ${t.flat}</div></div><div><small class="muted">多頭家數比</small><div class="score">${fmt(t.breadth,0)}%</div><div class="muted">平均漲跌 ${pct(t.avgChange)}</div></div></div><div class="grid" style="margin-top:10px">${metric("市場成交量",`${fmt(t.totalVolume,0)} 張`)}${metric("外資合計",`${fmt(t.foreign,0)} 張`)}${metric("三大法人合計",`${fmt(t.inst,0)} 張`)}${metric("環境信心",`${t.confidence}%`)}</div></div>\n  ${statusCard()}\n  <div class="card"><h3>產業相對強弱</h3><div class="rank-list">${t.industries.slice(0,6).map((t,s)=>`<div class="rank"><b>${s+1}</b><span><b>${t.industry}</b><small class="muted"> ${t.count} 檔 · 上漲家數 ${fmt(t.breadth,0)}%</small></span><b class="${cls(t.avgChange)}">${pct(t.avgChange)}</b></div>`).join("")}</div></div>\n  ${s("機會分數排行",l,t=>`${opportunityScore(t)} 分`)}${s("月營收年增排行",a,t=>pct(t.rev))}${s("三大法人買超排行",e,t=>`${fmt(t.inst,0)} 張`)}${disclaimer()}`}function opportunityCard(t){return`<article class="card accent clickable" data-detail="${t.symbol}"><div class="head"><div><b>${t.name}</b><div class="muted">${t.symbol} · ${t.industry}</div></div><div><small class="muted">機會分數</small><div class="score">${opportunityScore(t)}</div></div></div><div><span class="price">${fmt(t.close)}</span> <b class="${cls(t.change)}">${pct(t.change)}</b></div><div class="grid">${metric("月營收年增",pct(t.rev),t.revPeriod||"最新公開月")}${metric("月營收月增",pct(t.revMom))}${metric(t.roeEstimated?"年化推估 ROE":"ROE",null==t.roe?reasonDash("API 未回傳"):`${fmt(t.roe)}%`,t.roePeriod||"")}${metric("本益比",valueOrReason(t.pe))}</div><div class="rules" style="margin-top:10px"><span>成交量 ${fmt(t.volume,0)} 張</span>${null!=t.foreign?`<span>外資 ${fmt(t.foreign,0)} 張</span>`:""}<span>${t.industry}</span></div><div class="row" style="margin-top:10px"><button class="btn grow" data-forecast="${t.symbol}">深度預測</button><button class="btn secondary" data-watch="${t.symbol}">${isWatched(t.symbol)?"★ 已自選":"＋自選"}</button></div></article>`}function opportunitiesPage(){const t=S.stocks.filter(opportunityEligible).sort((t,s)=>opportunityScore(s)-opportunityScore(t));return`<h2>機會股</h2><p class="muted">月營收成長為核心，再綜合財報品質、估值、法人與流動性固定計分。</p><div class="card"><h3>固定門檻</h3><div class="rules"><span>月營收年增 ≥ 10%</span><span>成交量 ≥ 500 張</span><span>本益比 ≤ 35</span><span>ROE ≥ 8%（有資料時）</span><span>排除已確認風險股</span></div></div>${statusCard()}${t.length?`<div class="list two-col">${t.map(opportunityCard).join("")}</div>`:'<div class="card empty"><h3>目前沒有完整符合條件的股票</h3><p class="muted">可能是資料仍在載入，或目前沒有股票同時達到固定門檻。</p></div>'}${disclaimer()}`}function stockSearchResults(t,s){const a=t.trim().toLowerCase();if(!a)return"";const e=S.stocks.filter(t=>t.symbol.includes(a)||t.name.toLowerCase().includes(a)).slice(0,12);return e.length?`<div class="search-results">${e.map(t=>`<button class="search-result" ${s}="${t.symbol}"><span><b>${t.name}</b><small class="muted"> ${t.symbol} · ${t.industry}</small></span><span class="${cls(t.change)}">${pct(t.change)}</span></button>`).join("")}</div>`:'<div class="muted" style="margin-top:10px">找不到符合的股票</div>'}function forecastPage(){const t=[...S.stocks].filter(t=>null!=t.rev).sort((t,s)=>opportunityScore(s)-opportunityScore(t)).slice(0,8);return`<h2>未來漲跌預測</h2><p class="muted">整合歷史日線、MA、RSI、MACD、布林通道、ATR、量價、基本面、法人籌碼、大盤與產業環境。</p><div class="notice"><b>僅供參考使用</b><br>${DISCLAIMER}</div><div class="card"><h3>搜尋股票</h3><div class="search-row"><input id="forecastSearch" value="${esc(S.forecastQuery)}" placeholder="輸入代號或名稱，例如 3702 大聯大"><button id="forecastSearchBtn" class="btn">搜尋</button></div>${stockSearchResults(S.forecastQuery,"data-forecast")}</div><div class="card"><h3>優先分析清單</h3><div class="rank-list">${t.map((t,s)=>`<div class="rank clickable" data-forecast="${t.symbol}"><b>${s+1}</b><span><b>${t.name}</b><small class="muted"> ${t.symbol}</small></span><b>${opportunityScore(t)} 分</b></div>`).join("")}</div></div>${disclaimer()}`}function predictionStats(){const t=getPredictions(),s=t.filter(t=>t.evaluated_at),a=s.filter(t=>Date.now()-new Date(t.prediction_date).getTime()<=2592e6),e=s.filter(t=>Date.now()-new Date(t.prediction_date).getTime()<=7776e6),l=t=>t.length?t.filter(t=>t.is_correct).length/t.length*100:null;return{rows:t,evaluated:s,rate30:l(a),rate90:l(e),pending:t.filter(t=>!t.evaluated_at).length}}function verifyPage(){const t=predictionStats(),s=S.verifySymbol?S.stocks.find(t=>t.symbol===S.verifySymbol):null,a=s?[...S.backtestCache.entries()].find(([t])=>t.startsWith(s.symbol+"-"))?.[1]:null;return`<h2>預測驗證</h2><p class="muted">保存每次預測，五個交易日後比對實際結果；另提供不使用未來資料的技術面走勢回測。</p><div class="stat-strip">${metric("已評估",fmt(t.evaluated.length,0))}${metric("待評估",fmt(t.pending,0))}${metric("近 30 日命中率",null==t.rate30?"尚無樣本":`${fmt(t.rate30,1)}%`)}${metric("近 90 日命中率",null==t.rate90?"尚無樣本":`${fmt(t.rate90,1)}%`)}</div>\n  <div class="card"><h3>選擇股票進行歷史驗證</h3><div class="search-row"><input id="verifySearch" value="${esc(S.verifyQuery)}" placeholder="股票代號或名稱"><button id="verifySearchBtn" class="btn">搜尋</button></div>${stockSearchResults(S.verifyQuery,"data-verify")}</div>\n  ${s?`<div class="card accent"><div class="head"><div><h3>${s.name} ${s.symbol}</h3><div class="muted">技術面走勢回測，每 5 個交易日取樣一次</div></div><button class="btn small-btn" id="runBacktest" data-symbol="${s.symbol}">${a?"重新回測":"開始回測"}</button></div>${a?backtestHtml(a):'<div class="muted">按下開始回測後，會讀取近 12 個月日線並驗證方向。</div>'}</div>`:""}\n  <div class="card"><h3>最近預測紀錄</h3>${t.rows.length?`<div class="table-wrap"><table><thead><tr><th>股票／日期</th><th>預測</th><th>信心</th><th>實際</th><th>結果</th></tr></thead><tbody>${t.rows.slice(0,30).map(t=>`<tr><td>${t.stock_name||t.symbol}<br><small class="muted">${t.prediction_date}</small></td><td>${directionLabel(t.predicted_direction)}</td><td>${fmt(t.confidence,0)}%</td><td>${null==t.actual_return_pct?"待評估":pct(t.actual_return_pct)}</td><td>${t.evaluated_at?t.is_correct?'<span class="tag">正確</span>':'<span class="tag bad">不符</span>':'<span class="tag info">等待中</span>'}</td></tr>`).join("")}</tbody></table></div>`:'<div class="empty muted">尚未產生預測紀錄。開啟任一股票的深度預測後會自動保存。</div>'}</div>\n  <div class="notice">命中率只反映既有樣本，樣本不足或市場狀態改變時，不代表未來仍有相同表現。</div>${disclaimer()}`}function directionLabel(t){return"up"===t?"偏多":"down"===t?"偏空":"震盪"}function backtestHtml(t){return`<div class="grid" style="margin-top:12px">${metric("回測樣本",fmt(t.count,0))}${metric("方向命中率",null==t.hitRate?"—":`${fmt(t.hitRate,1)}%`)}${metric("樣本平均報酬",pct(t.avgReturn))}${metric("平均獲利／虧損",`${pct(t.avgWin)} / ${pct(t.avgLoss)}`)}</div><div class="table-wrap" style="margin-top:10px"><table><thead><tr><th>日期</th><th>預測</th><th>5 日報酬</th><th>結果</th></tr></thead><tbody>${t.samples.slice(-12).reverse().map(t=>`<tr><td>${t.date}</td><td>${directionLabel(t.pred)}</td><td class="${cls(t.ret)}">${pct(t.ret)}</td><td>${t.correct?"✓":"×"}</td></tr>`).join("")}</tbody></table></div><div class="muted small" style="margin-top:8px">此回測只使用當時之前的價格與成交量，不套用現在的月營收或財報資料，避免偷看未來。</div>`}function journalStats(){const t=getJournal(),s=t.filter(t=>null!=t.return_pct),a=s.filter(t=>t.return_pct>0),e=t.filter(t=>null!=t.followed_plan);return{all:t,closed:s,winRate:s.length?a.length/s.length*100:null,avgReturn:mean(s.map(t=>t.return_pct)),followRate:e.length?e.filter(t=>t.followed_plan).length/e.length*100:null}}function minePage(){return`<h2>我的</h2><div class="segmented"><button data-mine="watch" class="${"watch"===S.mineSub?"active":""}">自選清單</button><button data-mine="journal" class="${"journal"===S.mineSub?"active":""}">投資紀錄</button></div>${"watch"===S.mineSub?watchSection():journalSection()}${disclaimer()}`}function watchSection(){const t=getWatchlist().map(t=>({item:t,stock:S.stocks.find(s=>s.symbol===t.symbol)})).filter(t=>t.stock);return t.length?`<div class="list two-col">${t.map(({item:t,stock:s})=>{const a=t.addedPrice&&s.close?100*(s.close/t.addedPrice-1):null;return`<div class="card clickable" data-detail="${s.symbol}"><div class="head"><div><b>${s.name}</b><div class="muted">${s.symbol} · ${s.industry}</div></div><button class="icon-btn" data-watch="${s.symbol}">移除</button></div><div class="grid">${metric("目前價格",fmt(s.close))}${metric("加入後漲跌",`<span class="${cls(a)}">${pct(a)}</span>`)}${metric("月營收年增",pct(s.rev))}${metric("機會分數",opportunityScore(s))}</div><button class="btn" data-forecast="${s.symbol}" style="width:100%;margin-top:10px">查看趨勢預測</button></div>`}).join("")}</div>`:'<div class="card empty"><h3>尚未加入自選股票</h3><p class="muted">可在機會股或股票詳細頁加入。</p></div>'}function journalSection(){const t=journalStats(),s=`<div class="stat-strip">${metric("紀錄筆數",fmt(t.all.length,0))}${metric("已完成交易",fmt(t.closed.length,0))}${metric("勝率",null==t.winRate?"尚無樣本":`${fmt(t.winRate,1)}%`)}${metric("遵守計畫率",null==t.followRate?"尚無資料":`${fmt(t.followRate,1)}%`)}</div><div class="row"><button id="newJournal" class="btn grow">＋新增投資紀錄</button><button id="exportJournal" class="btn secondary">匯出 JSON</button></div>`;return t.all.length?`${s}<div class="list">${t.all.map(t=>`<div class="card journal-item ${t.action}"><div class="head"><div><b>${t.stock_name||t.symbol} ${t.symbol}</b><div class="muted">${t.entry_date} · ${actionLabel(t.action)} · ${horizonLabel(t.horizon)}</div></div>${null!=t.return_pct?`<b class="${cls(t.return_pct)}">${pct(t.return_pct)}</b>`:""}</div>${t.thesis?`<p>${esc(t.thesis)}</p>`:""}<div class="rules">${t.risk_plan?`<span>風險：${esc(t.risk_plan)}</span>`:""}${t.target_plan?`<span>目標：${esc(t.target_plan)}</span>`:""}${null!=t.followed_plan?`<span>遵守計畫：${t.followed_plan?"是":"否"}</span>`:""}</div><div class="row" style="margin-top:10px"><button class="btn secondary" data-edit-journal="${t.local_id||t.id}">編輯</button><button class="btn danger" data-delete-journal="${t.local_id||t.id}">刪除</button></div></div>`).join("")}</div>`:`${s}<div class="card empty"><h3>尚未建立投資紀錄</h3><p class="muted">記錄當時理由、預期、風險與結果，之後才能檢查自己是否遵守計畫。</p></div>`}function actionLabel(t){return{observe:"觀察",buy:"買入紀錄",sell:"賣出紀錄",review:"事後檢討"}[t]||t}function horizonLabel(t){return{short:"短線 1–5 日",swing:"波段 1–4 週",medium:"中期 1–6 月",long:"長期 6 月以上"}[t]||"未設定期間"}